import React from 'react';
import { NavLink, Link, useLocation } from 'react-router-dom';
import { Icon } from './Icon';
import { useAuth } from '@/context';

interface BillingSidebarProps {
    isCollapsed: boolean;
    isOpen: boolean;
    onClose: () => void;
}

