                                >
                                    {({isActive}) => (<>
                                        <Icon name={item.icon} fixedWidth className={`text-lg ${isCollapsed ? '' : 'mr-3'} ${isActive ? iconActiveColor : iconBaseColor} ${isActive ? '' : iconHoverColor}`} />
