              </Link>
            ) : (
              <span className="text-[#293c51] dark:text-gray-200 font-medium">{item.label}</span>
            )}
            {index < items.length - 1 && (
              <Icon name="fas fa-chevron-right" className="w-4 h-4 mx-1 text-gray-400 dark:text-gray-500" />
            )}
          </li>
        ))}
      </ol>
    </nav>
  );
