                    {organizations.map(org => (
                        <button
                            key={org.id}
                            onClick={() => setActiveOrgId(org.id)}
                            className={`w-full text-left px-5 py-3 rounded-lg text-sm font-semibold transition-all duration-200
                                ${activeOrgId === org.id 
                                    ? 'bg-[#679a41] text-white shadow-md' 
